class Solution:
    def countPalindromePaths(self, parent, s):
        from collections import Counter
        n = len(parent)

        def path_chars(u, v):
            anc_u = set()
            cur = u
            path_u = []
            while cur != -1:
                anc_u.add(cur)
                path_u.append(cur)
                cur = parent[cur]
            cur = v
            path_v = []
            while cur not in anc_u:
                path_v.append(cur)
                cur = parent[cur]
            lca = cur
            chars = []
            for node in path_u:
                if node == lca:
                    break
                chars.append(s[node])
            for node in reversed(path_v):
                chars.append(s[node])
            return chars

        count = 0
        for u in range(n):
            for v in range(u + 1, n):
                c = Counter(path_chars(u, v))
                odd = sum(1 for cnt in c.values() if cnt % 2 == 1)
                if odd <= 1:
                    count += 1
        return count

